    async creditUser (userId, amount, reason, adminId, adminName) {
        try {
            // Get current user
            const user = await userService.getById(userId);
            if (!user) throw new Error('User not found');
            const balanceBefore = user.credits;
            const balanceAfter = balanceBefore + amount;
            // Update user credits
            await userService.update(userId, {
                credits: balanceAfter
            });
            // Create credit transaction record
            await this.create({
                userId,
                adminId,
                adminName,
                type: 'credit',
                amount,
                reason,
                balanceBefore,
                balanceAfter
            });
            // Create transaction record
            await transactionService.create({
                userId,
                type: 'admin_credit',
                amount,
                description: `Admin credit: ${reason}`,
                status: 'completed'
            });
            return balanceAfter;
        } catch (error) {
            console.error('Error crediting user:', error);
            throw error;
        }
    },
    async debitUser (userId, amount, reason, adminId, adminName) {
        try {
            // Get current user
            const user = await userService.getById(userId);
            if (!user) throw new Error('User not found');
            const balanceBefore = user.credits;
            const balanceAfter = Math.max(0, balanceBefore - amount); // Prevent negative balance
            // Update user credits
            await userService.update(userId, {
                credits: balanceAfter
            });
            // Create debit transaction record
            await this.create({
                userId,
                adminId,
                adminName,
                type: 'debit',
                amount,
                reason,
                balanceBefore,
                balanceAfter
            });
            // Create transaction record
            await transactionService.create({
                userId,
                type: 'admin_debit',
                amount: -amount,
                description: `Admin debit: ${reason}`,
                status: 'completed'
            });
            return balanceAfter;
        } catch (error) {
            console.error('Error debiting user:', error);
            throw error;
        }
    }
